import numpy as np

class NeuralNetwork:
    def __init__(self):
        self.weights1 = np.random.rand(2, 4)
        self.weights2 = np.random.rand(4, 1)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def backward(self, X, y, output, hidden):
        error = y - output
        d_output = error * self.sigmoid_derivative(output)
        error_hidden = d_output.dot(self.weights2.T)
        d_hidden = error_hidden * self.sigmoid_derivative(hidden)
        self.weights2 += hidden.T.dot(d_output)  # update
        self.weights1 += X.T.dot(d_hidden)

