positive_words = {'great', 'excellent', 'amazing', 'good', 'love', 'fantastic'}
negative_words = {'terrible', 'bad', 'awful', 'hate', 'poor', 'refund'}

def classify_sentiment(text):
    words = set(text.lower().split())
    pos = len(words & positive_words)
    neg = len(words & negative_words)
    if pos > neg:
        return 'positive'
    elif neg > pos:
        return 'negative'
    return 'neutral'

print(classify_sentiment('The product is absolutely terrible and I want a refund'))

